def validate_payload(payload: dict) -> tuple[bool, str]:
    """
    Validate the webhook payload structure and required fields.
    """
    required_fields = ["event_type", "event_id", "timestamp", "data"]

    for field in required_fields:
        if field not in payload:
            return False, f"Missing required field: {field}"

    # Validate event type
    event_type = payload.get("event_type", "")
    if event_type not in SUPPORTED_EVENTS:
        return False, f"Unsupported event type: {event_type}"

    # Validate event_id is a non-empty string
    event_id = payload.get("event_id", "")
    if not isinstance(event_id, str) or not event_id.strip():
        return False, "event_id must be a non-empty string"

    # Validate timestamp
    timestamp = payload.get("timestamp")
    if timestamp:
        try:
            if isinstance(timestamp, str):
                event_time = datetime.fromisoformat(timestamp.replace("Z", "+00:00"))
            elif isinstance(timestamp, (int, float)):
                event_time = datetime.fromtimestamp(timestamp, tz=timezone.utc)
            else:
                return False, "Invalid timestamp format"

            # Reject events older than 5 minutes (replay protection)
            now = datetime.now(timezone.utc)
            age_seconds = abs((now - event_time).total_seconds())
            if age_seconds > 300:
                return False, f"Event timestamp too old ({age_seconds:.0f}s). Possible replay attack."
        except (ValueError, TypeError, OSError) as e:
            return False, f"Invalid timestamp: {str(e)}"

    # Validate data field
    data = payload.get("data")
    if not isinstance(data, dict):
        return False, "data must be a JSON object"

    # Validate payment-specific fields
    if event_type.startswith("payment."):
        if "payment_id" not in data:
            return False, "Payment events must include data.payment_id"
        if "amount" not in data:
            return False, "Payment events must include data.amount"
        if "currency" not in data:
            return False, "Payment events must include data.currency"

        amount = data.get("amount")
        if not isinstance(amount, (int, float)) or amount < 0:
            return False, "data.amount must be a non-negative number"

    return True, ""


